import (
    "context"
    "database/sql"
    "fmt"

    entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
    "github.com/openmeterio/openmeter/pkg/framework/entutils"
    "github.com/openmeterio/openmeter/pkg/framework/transaction"
)

type myAdapter struct {
    db *entdb.Client
}

// Tx implements TxCreator
func (a *myAdapter) Tx(ctx context.Context) (context.Context, transaction.Driver, error) {
    txCtx, rawCfg, drv, err := a.db.HijackTx(ctx, &sql.TxOptions{ReadOnly: false})
    if err != nil {
        return nil, nil, fmt.Errorf("hijack tx: %w", err)
    }
    return txCtx, entutils.NewTxDriver(drv, rawCfg), nil
}

// Self implements TxUser
func (a *myAdapter) Self() *myAdapter { return a }

// WithTx implements TxUser
func (a *myAdapter) WithTx(ctx context.Context, tx *entutils.TxDriver) *myAdapter {
    txClient := entdb.NewTxClientFromRawConfig(ctx, *tx.GetConfig())
    return &myAdapter{db: txClient.Client()}
}

// Create uses TransactingRepo to honor any ctx-bound transaction
func (a *myAdapter) Create(ctx context.Context, name string) (*entdb.MyEntity, error) {
    return entutils.TransactingRepo(ctx, a, func(ctx context.Context, repo *myAdapter) (*entdb.MyEntity, error) {
        return repo.db.MyEntity.Create().SetName(name).Save(ctx)
    })
}
